  pairing_logic = '{"pairs_well_before":["Cossack Squat Pry","Lateral Lunge","Bear Crawl"],"pairs_well_after":["90/90 Hip Switch","Cat-Cow"],"good_for_sessions":["general_warmup","squat_prep","crawling_prep"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Sharp pain, joint pinching, numbness, tingling, or dizziness appears.","The athlete cannot control the starting position even after regression.","The session needs immediate high-output work and this drill would become a long, fatigue-creating block.","The athlete treats the drill as passive stretching or a race instead of active mobility."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex mobility demo recommended","Joint mobility warm-up principles","Controlled articular rotation concepts"],"internal_notes":["Film one clean regression and one clean progression.","Emphasize position-access work, not passive stretching for its own sake.","Best before related strength, speed, skill, field, court, tumbling, or game prep."]}'::jsonb,
  updated_at = now()
