-- Deep Squat Pry with Reach (deep-squat-pry-with-reach) [merge]
UPDATE coaching.exercise SET
  name = 'Deep Squat Pry with Reach',
  description = 'Sink into a comfortable deep squat, gently pry the knees out, reach one arm up, then switch sides while breathing into the bottom position.',
  card_summary = 'Dynamic mobility drill that opens ankles, hips, adductors, thoracic reach, and bottom-squat comfort. Use it when the athlete needs usable range of motion that carries into warm-ups, workouts, or games.',
