-- Quadruped Wrist Pronation-Supination Shifts (quadruped-wrist-pronation-supination-shifts) [merge]
UPDATE coaching.exercise SET
  name = 'Quadruped Wrist Pronation-Supination Shifts',
  description = 'Rock in quadruped while gently changing hand orientation to expose the wrists, palms, and forearms to controlled weight bearing.',
  card_summary = 'Dynamic mobility drill that opens wrist extension, forearm rotation, and low-load hand-support preparation. Use it when the athlete needs usable range of motion that carries into warm-ups, workouts, or games.',
  coach_language = 'Primary subrole: Mobilize. Coach slow-to-smooth motion, clean breathing, and position ownership. This is flexibility combined with motion; stop before the athlete turns it into fatigue, passive stretching, or sloppy range chasing.',
  athlete_language = 'Move smoothly, breathe through the range, and own the position you create.',
  movement_family = 'Wrist access',
  primary_phase_key = 'prepare_and_access',
  phase_subrole = 'mobilize',
  primary_order_slot = 'wrist_forearm_access',
  default_sets = 1,
  default_reps = 6,
  default_work_seconds = 45,
  default_rest_seconds = 0,
  est_seconds_per_set = 45,
  movement_requirements = '{"primary_joint_actions":["wrist_extension","forearm_pronation","forearm_supination","weight_bearing_tolerance"],"primary_tissues":["wrist_flexors","wrist_extensors","forearm_pronators","forearm_supinators"],"primary_motor_control_demands":["controlled_range_ownership","posture_under_motion","smooth_transition_timing"],"postural_shape":"dynamic_prepare_position","breathing_demand":"controlled nasal or relaxed diaphragmatic breathing","balance_demand":"stable to moderate","coordination_demand":"low to moderate","impact_level":0}'::jsonb,
  coaching_execution = '{"movement_description":"Rock in quadruped while gently changing hand orientation to expose the wrists, palms, and forearms to controlled weight bearing.","setup":["Start in a pain-free range with enough space to move slowly and reset between reps.","Set the ribs over the pelvis and keep the neck relaxed before initiating movement.","Use support, a wall, a mat, or a shorter range if balance or joint comfort limits quality.","Bias the drill toward wrist extension, forearm rotation, and low-load hand-support preparation, not toward maximum speed or fatigue."],"execution_steps":["Move into the first position slowly enough to feel where range is available.","Breathe through the transition and keep the target joints moving without borrowing motion from the low back or neck.","Pause briefly at the usable end range, then return or step through with the same alignment.","Repeat only while the motion gets cleaner or stays clean; stop when compensation increases."],"coach_cues":["Smooth first, bigger second.","Breathe into the range; do not force it.","Own the position before you move out of it.","Keep the motion where the drill is supposed to happen."],"athlete_cues":["Slow is smooth; smooth becomes athletic.","No pinching, no rushing, no sloppy reps.","Move like this range has to work in a game."],"breathing_cues":["Inhale before the transition if needed; exhale gently into the new range.","Keep the jaw and neck relaxed.","Do not hold the breath to force range."],"common_faults":["Chasing a bigger range by twisting through the low back or collapsing posture.","Rushing transitions until mobility turns into uncontrolled momentum.","Ignoring pinching, numbness, dizziness, or joint irritation.","Letting balance demands hide the actual mobility target."],"quality_gate":["No sharp pain or joint pinch.","Breathing stays calm and controlled.","The target joint action is visible without major compensation.","Final rep looks as controlled as the first rep."],"stop_signs":["Sharp pain, numbness, tingling, dizziness, or escalating discomfort.","Loss of posture for more than one rep in a row.","Athlete turns the drill into speed, fatigue, or competition instead of mobility.","Range decreases or compensation increases as reps continue."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Handstand Prep","Bear Crawl","Push-Up Prep"],"pairs_well_after":["Quadruped Scapular Glide","Cat-Cow"],"good_for_sessions":["general_warmup","crawling_prep","tumbling_prep"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Sharp pain, joint pinching, numbness, tingling, or dizziness appears.","The athlete cannot control the starting position even after regression.","The session needs immediate high-output work and this drill would become a long, fatigue-creating block.","The athlete treats the drill as passive stretching or a race instead of active mobility."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex mobility demo recommended","Joint mobility warm-up principles","Controlled articular rotation concepts"],"internal_notes":["Film one clean regression and one clean progression.","Emphasize position-access work, not passive stretching for its own sake.","Best before related strength, speed, skill, field, court, tumbling, or game prep."]}'::jsonb,
  updated_at = now()
WHERE slug = 'quadruped-wrist-pronation-supination-shifts';

