-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and physiological qualities for dynamic mobility and session readiness.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('walking-knee-hug-to-calf-raise', 'The drill exposes hip flexion, glute length, foot tripod, and ankle stiffness while the athlete is actively controlling posture, breathing, and transitions. That turns available range into sport-usable mobility instead of passive flexibility that disappears once movement speed increases.', 'Belongs in Prepare & Access / Mobilize because it increases movement access and readiness before intensity, load, sprinting, cutting, jumping, tumbling, or gameplay. It should not create meaningful fatigue before Output or skill work.', 'Prepare & Access phase after a brief temperature raise and before higher-intent skill, speed, strength, or sport work that needs hip flexion, glute length, foot tripod, and ankle stiffness.', 'Rushing for reps, forcing end range through pinching, or turning the drill into a conditioning station. The goal is smoother access and control, not exhaustion or passive stretching for time.', 'Scale by range, support, tempo, and total volume before adding complexity. Athletes should keep breathing, alignment, and repeatable motion as the progression standard.'),
  ('walking-quad-pull-with-overhead-reach', 'The drill exposes front-of-hip length, quad length, tall posture, and shoulder reach while the athlete is actively controlling posture, breathing, and transitions. That turns available range into sport-usable mobility instead of passive flexibility that disappears once movement speed increases.', 'Belongs in Prepare & Access / Mobilize because it increases movement access and readiness before intensity, load, sprinting, cutting, jumping, tumbling, or gameplay. It should not create meaningful fatigue before Output or skill work.', 'Prepare & Access phase after a brief temperature raise and before higher-intent skill, speed, strength, or sport work that needs front-of-hip length, quad length, tall posture, and shoulder reach.', 'Rushing for reps, forcing end range through pinching, or turning the drill into a conditioning station. The goal is smoother access and control, not exhaustion or passive stretching for time.', 'Scale by range, support, tempo, and total volume before adding complexity. Athletes should keep breathing, alignment, and repeatable motion as the progression standard.'),
  ('open-gate-close-gate-walk', 'The drill exposes hip rotation during stepping, pelvis control, and gait rhythm while the athlete is actively controlling posture, breathing, and transitions. That turns available range into sport-usable mobility instead of passive flexibility that disappears once movement speed increases.', 'Belongs in Prepare & Access / Mobilize because it increases movement access and readiness before intensity, load, sprinting, cutting, jumping, tumbling, or gameplay. It should not create meaningful fatigue before Output or skill work.', 'Prepare & Access phase after a brief temperature raise and before higher-intent skill, speed, strength, or sport work that needs hip rotation during stepping, pelvis control, and gait rhythm.', 'Rushing for reps, forcing end range through pinching, or turning the drill into a conditioning station. The goal is smoother access and control, not exhaustion or passive stretching for time.', 'Scale by range, support, tempo, and total volume before adding complexity. Athletes should keep breathing, alignment, and repeatable motion as the progression standard.'),
  ('dynamic-leg-swing-front-to-back', 'The drill exposes active hip flexion and extension without trunk compensation while the athlete is actively controlling posture, breathing, and transitions. That turns available range into sport-usable mobility instead of passive flexibility that disappears once movement speed increases.', 'Belongs in Prepare & Access / Mobilize because it increases movement access and readiness before intensity, load, sprinting, cutting, jumping, tumbling, or gameplay. It should not create meaningful fatigue before Output or skill work.', 'Prepare & Access phase after a brief temperature raise and before higher-intent skill, speed, strength, or sport work that needs active hip flexion and extension without trunk compensation.', 'Rushing for reps, forcing end range through pinching, or turning the drill into a conditioning station. The goal is smoother access and control, not exhaustion or passive stretching for time.', 'Scale by range, support, tempo, and total volume before adding complexity. Athletes should keep breathing, alignment, and repeatable motion as the progression standard.'),
  ('dynamic-leg-swing-lateral', 'The drill exposes adductor length, lateral hip access, and pelvis control while the athlete is actively controlling posture, breathing, and transitions. That turns available range into sport-usable mobility instead of passive flexibility that disappears once movement speed increases.', 'Belongs in Prepare & Access / Mobilize because it increases movement access and readiness before intensity, load, sprinting, cutting, jumping, tumbling, or gameplay. It should not create meaningful fatigue before Output or skill work.', 'Prepare & Access phase after a brief temperature raise and before higher-intent skill, speed, strength, or sport work that needs adductor length, lateral hip access, and pelvis control.', 'Rushing for reps, forcing end range through pinching, or turning the drill into a conditioning station. The goal is smoother access and control, not exhaustion or passive stretching for time.', 'Scale by range, support, tempo, and total volume before adding complexity. Athletes should keep breathing, alignment, and repeatable motion as the progression standard.'),
  ('ankle-knee-to-wall-rocker', 'The drill exposes ankle dorsiflexion, heel contact, and knee-over-foot tracking while the athlete is actively controlling posture, breathing, and transitions. That turns available range into sport-usable mobility instead of passive flexibility that disappears once movement speed increases.', 'Belongs in Prepare & Access / Mobilize because it increases movement access and readiness before intensity, load, sprinting, cutting, jumping, tumbling, or gameplay. It should not create meaningful fatigue before Output or skill work.', 'Prepare & Access phase after a brief temperature raise and before higher-intent skill, speed, strength, or sport work that needs ankle dorsiflexion, heel contact, and knee-over-foot tracking.', 'Rushing for reps, forcing end range through pinching, or turning the drill into a conditioning station. The goal is smoother access and control, not exhaustion or passive stretching for time.', 'Scale by range, support, tempo, and total volume before adding complexity. Athletes should keep breathing, alignment, and repeatable motion as the progression standard.'),
  ('down-dog-calf-pedal', 'The drill exposes calf length, hamstring tone, and shoulder-supported hip hinge while the athlete is actively controlling posture, breathing, and transitions. That turns available range into sport-usable mobility instead of passive flexibility that disappears once movement speed increases.', 'Belongs in Prepare & Access / Mobilize because it increases movement access and readiness before intensity, load, sprinting, cutting, jumping, tumbling, or gameplay. It should not create meaningful fatigue before Output or skill work.', 'Prepare & Access phase after a brief temperature raise and before higher-intent skill, speed, strength, or sport work that needs calf length, hamstring tone, and shoulder-supported hip hinge.', 'Rushing for reps, forcing end range through pinching, or turning the drill into a conditioning station. The goal is smoother access and control, not exhaustion or passive stretching for time.', 'Scale by range, support, tempo, and total volume before adding complexity. Athletes should keep breathing, alignment, and repeatable motion as the progression standard.'),
  ('short-foot-to-calf-raise-mobility-prep', 'The drill exposes foot tripod, arch control, and controlled ankle plantarflexion while the athlete is actively controlling posture, breathing, and transitions. That turns available range into sport-usable mobility instead of passive flexibility that disappears once movement speed increases.', 'Belongs in Prepare & Access / Mobilize because it increases movement access and readiness before intensity, load, sprinting, cutting, jumping, tumbling, or gameplay. It should not create meaningful fatigue before Output or skill work.', 'Prepare & Access phase after a brief temperature raise and before higher-intent skill, speed, strength, or sport work that needs foot tripod, arch control, and controlled ankle plantarflexion.', 'Rushing for reps, forcing end range through pinching, or turning the drill into a conditioning station. The goal is smoother access and control, not exhaustion or passive stretching for time.', 'Scale by range, support, tempo, and total volume before adding complexity. Athletes should keep breathing, alignment, and repeatable motion as the progression standard.'),
  ('a-march-mobility-with-arm-sweep', 'The drill exposes hip flexion rhythm, ankle position, posture, and opposite-arm swing while the athlete is actively controlling posture, breathing, and transitions. That turns available range into sport-usable mobility instead of passive flexibility that disappears once movement speed increases.', 'Belongs in Prepare & Access / Mobilize because it increases movement access and readiness before intensity, load, sprinting, cutting, jumping, tumbling, or gameplay. It should not create meaningful fatigue before Output or skill work.', 'Prepare & Access phase after a brief temperature raise and before higher-intent skill, speed, strength, or sport work that needs hip flexion rhythm, ankle position, posture, and opposite-arm swing.', 'Rushing for reps, forcing end range through pinching, or turning the drill into a conditioning station. The goal is smoother access and control, not exhaustion or passive stretching for time.', 'Scale by range, support, tempo, and total volume before adding complexity. Athletes should keep breathing, alignment, and repeatable motion as the progression standard.'),
  ('carioca-mobility-weave', 'The drill exposes hip rotation, trunk rhythm, lateral stepping, and gait coordination while the athlete is actively controlling posture, breathing, and transitions. That turns available range into sport-usable mobility instead of passive flexibility that disappears once movement speed increases.', 'Belongs in Prepare & Access / Mobilize because it increases movement access and readiness before intensity, load, sprinting, cutting, jumping, tumbling, or gameplay. It should not create meaningful fatigue before Output or skill work.', 'Prepare & Access phase after a brief temperature raise and before higher-intent skill, speed, strength, or sport work that needs hip rotation, trunk rhythm, lateral stepping, and gait coordination.', 'Rushing for reps, forcing end range through pinching, or turning the drill into a conditioning station. The goal is smoother access and control, not exhaustion or passive stretching for time.', 'Scale by range, support, tempo, and total volume before adding complexity. Athletes should keep breathing, alignment, and repeatable motion as the progression standard.'),
  ('90-90-hip-switch', 'The drill exposes hip internal and external rotation with pelvic control while the athlete is actively controlling posture, breathing, and transitions. That turns available range into sport-usable mobility instead of passive flexibility that disappears once movement speed increases.', 'Belongs in Prepare & Access / Mobilize because it increases movement access and readiness before intensity, load, sprinting, cutting, jumping, tumbling, or gameplay. It should not create meaningful fatigue before Output or skill work.', 'Prepare & Access phase after a brief temperature raise and before higher-intent skill, speed, strength, or sport work that needs hip internal and external rotation with pelvic control.', 'Rushing for reps, forcing end range through pinching, or turning the drill into a conditioning station. The goal is smoother access and control, not exhaustion or passive stretching for time.', 'Scale by range, support, tempo, and total volume before adding complexity. Athletes should keep breathing, alignment, and repeatable motion as the progression standard.'),
  ('shin-box-get-up-flow', 'The drill exposes hip rotation, trunk control, and ground-to-kneel transition while the athlete is actively controlling posture, breathing, and transitions. That turns available range into sport-usable mobility instead of passive flexibility that disappears once movement speed increases.', 'Belongs in Prepare & Access / Mobilize because it increases movement access and readiness before intensity, load, sprinting, cutting, jumping, tumbling, or gameplay. It should not create meaningful fatigue before Output or skill work.', 'Prepare & Access phase after a brief temperature raise and before higher-intent skill, speed, strength, or sport work that needs hip rotation, trunk control, and ground-to-kneel transition.', 'Rushing for reps, forcing end range through pinching, or turning the drill into a conditioning station. The goal is smoother access and control, not exhaustion or passive stretching for time.', 'Scale by range, support, tempo, and total volume before adding complexity. Athletes should keep breathing, alignment, and repeatable motion as the progression standard.'),
  ('half-kneeling-hip-flexor-rockback-with-reach', 'The drill exposes true hip extension, anterior-chain length, and rib-to-pelvis control while the athlete is actively controlling posture, breathing, and transitions. That turns available range into sport-usable mobility instead of passive flexibility that disappears once movement speed increases.', 'Belongs in Prepare & Access / Mobilize because it increases movement access and readiness before intensity, load, sprinting, cutting, jumping, tumbling, or gameplay. It should not create meaningful fatigue before Output or skill work.', 'Prepare & Access phase after a brief temperature raise and before higher-intent skill, speed, strength, or sport work that needs true hip extension, anterior-chain length, and rib-to-pelvis control.', 'Rushing for reps, forcing end range through pinching, or turning the drill into a conditioning station. The goal is smoother access and control, not exhaustion or passive stretching for time.', 'Scale by range, support, tempo, and total volume before adding complexity. Athletes should keep breathing, alignment, and repeatable motion as the progression standard.'),
