-- Dynamic mobility cluster validation education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_matters, programming_guidance, common_misuse
)
VALUES (
  'validation_rule',
  'dynamic_mobility_readiness',
  NULL,
  'Dynamic mobility without fatigue drift or wrong phase intent',
  'Prepare & Access Mobilize drills must open usable range with controlled motion and low RPE — not passive stretching marathons, conditioning circuits, or Output-speed intent.',
  'Mobility cards span gait prep, hip and spine access, shoulder and neck prep, ankle dorsiflexion, and full-body flows for athletes who need sport-usable range before skill, speed, strength, or gameplay.',
  'Usable mobility depends on active control, breathing, and joint alignment. Forcing end range, rushing transitions, or stacking volume before high-output work trains compensation and steals freshness.',
  'Place after a brief temperature raise and before higher-intent work. Scale by range, support, and tempo; stop when motion gets sloppy. Pair with activation or integrate when the session demands it.',
  'Do not program long passive holds, chase max reps until fatigued, or hide conditioning in Mobilize when the goal is access and readiness.'
)
